import React from "react";
import css from "./Registration.module.css"
import { Button, Input } from "antd";

const Registration = () => {

let value = Input.value

    return (
        <>
            <div className={css.wrapper} >
                <div className={css.InputBlock}>
                    <label className={css.label}>Nickname</label>
                    <Input required type="text" placeholder="Enter nickname" className={css.NickName} value={""}>{value}</Input>
                    <label className={css.label}>Chat name</label>
                    <Input required type="text" placeholder="Enter the chat name" className={css.ChatName} value={""}></Input>
                    <Button className={css.Button}>Войти</Button>
                </div>
            </div>
            <Button className={css.buttonAI}>Chat AI</Button>
        </>
    )
}

export default Registration;
